void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    vec2 uv2, uv3, dz;
    float ang2, c, s;

    vUv -= 0.5;
    vUv *= uAspect.xy;

vec3 ret1 = 0;
int anz = 6;
int n = 0;
while (n <= anz) {
    ang2 = 6.28*n/anz;
    c = cos(ang2);
    s = sin(ang2);
    uv2.x =  vUv.x*c - vUv.y*s;
    uv2.y =  vUv.x*s + vUv.y*c;
    uv2 *= uAspect.yx;
    uv2 += .5;
    uv2 = fract(uv2);
    neu = GetPixel(uv2) + GetBlur1(uv2);
    ret1 = max(ret1,neu);
n++;
}


rs2 = sin(vUv*18+vec2 (q5,q6))
      + 4*lum(ret1);;
float dots = clamp01(.04/length(rs2))-.0;

ret = q22*ret1 + 24*dots*(.2+q1*ret1/2);

  fragColor = ret;
}
